 1	//a text list that keeps each text in a separate line, shows an ellipsis and a tooltip if the text is too long
 2	
 3	import { TextList, TextListItem } from "@patternfly/react-core";
 4	import * as React from "react";
 5	import EllipsisToolTip from "./EllipsisTooltip";
 6	import "./enhanced-text-list.css";
 7	
 8	const EnhancedTextList: React.FC<{ textList: string[] }> = ({ textList }) => (
 9	  <TextList className="nhc-enhanced-text-list__list">
10	    {textList.map((text, idx) => (
11	      <EllipsisToolTip content={text} key={idx}>
12	        <TextListItem className="nhc-enhanced-text-list__list-item">
13	          {text}
14	        </TextListItem>
15	      </EllipsisToolTip>
16	    ))}
17	  </TextList>
18	);
19	
20	export default EnhancedTextList;

